def tengeneza_vcf(data, jina_la_faili="Dodoma_Contacts.vcf"):
    # 1. Extract namba tu kwa kutumia Regular Expressions (Regex)
    # Hii inatafuta namba zote bila kujali nafasi au alama nyingine
    cleaned_numbers = re.findall(r'\+?\d[\d\s\-\(\)]{8,}\d', data)
    
    contacts = []
    for num in cleaned_numbers:
        # Safisha namba iwe safi kabisa (ondoa spaces, mabano, n.k.)
        pure_num = re.sub(r'[\s\-\(\)]', '', num)
        if len(pure_num) >= 10: # Hakikisha ni namba halali
            contacts.append(pure_num)
    
    # Ondoa namba zinazojirudia (Duplicates)
    contacts = list(dict.fromkeys(contacts))
    
    # 2. Tengeneza faili la VCF (vCard)
    with open(jina_la_faili, 'w', encoding='utf-8') as f:
        for i, phone in enumerate(contacts, 1):
            f.write("BEGIN:VCARD\n")
            f.write("VERSION:3.0\n")
            f.write(f"FN:Dodoma {i}\n")  # Itatokea kama Dodoma 1, Dodoma 2...
            f.write(f"TEL;TYPE=CELL:{phone}\n")
            f.write("END:VCARD\n")
            
    print(f"✅ Fanikiwa! Namba {len(contacts)} zimehifadhiwa kwenye '{jina_la_faili}'")
    print("Sasa rusha hili faili kwenye simu yako na ulifungue (Open) ili zi-save.")

